-- ============================================
-- BASE DE DONNEES - UNIV-SCHEDULER
-- Universite Iba Der Thiam de Thies (UIDT)
-- Annee academique 2024-2025
-- Compatible MySQL 5.7+ / MariaDB 10.3+
-- ============================================

SET FOREIGN_KEY_CHECKS = 0;
SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;

-- Creation de la base de donnees
CREATE DATABASE IF NOT EXISTS univ_scheduler
  CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE univ_scheduler;

-- Suppression des tables existantes (ordre inverse des FK)
DROP TABLE IF EXISTS `notifications`;
DROP TABLE IF EXISTS `reservations`;
DROP TABLE IF EXISTS `cours`;
DROP TABLE IF EXISTS `salle_equipements`;
DROP TABLE IF EXISTS `salles`;
DROP TABLE IF EXISTS `equipements`;
DROP TABLE IF EXISTS `matieres`;
DROP TABLE IF EXISTS `classes`;
DROP TABLE IF EXISTS `utilisateurs`;
DROP TABLE IF EXISTS `types_salle`;
DROP TABLE IF EXISTS `batiments`;

-- ============================================
-- STRUCTURE DES TABLES
-- ============================================

CREATE TABLE `batiments` (
  `id`            INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `nom`           VARCHAR(100) NOT NULL,
  `localisation`  VARCHAR(200) DEFAULT NULL,
  `nombre_etages` INT UNSIGNED NOT NULL DEFAULT 1,
  `date_creation` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `types_salle` (
  `id`      INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `libelle` VARCHAR(50) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_types_salle_libelle` (`libelle`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `salles` (
  `id`            INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `numero`        VARCHAR(20) NOT NULL,
  `nom`           VARCHAR(100) DEFAULT NULL,
  `capacite`      INT UNSIGNED NOT NULL,
  `etage`         INT NOT NULL DEFAULT 0,
  `type_salle_id` INT UNSIGNED NOT NULL,
  `batiment_id`   INT UNSIGNED NOT NULL,
  `disponible`    TINYINT(1) NOT NULL DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_salle_num_bat` (`numero`, `batiment_id`),
  KEY `fk_salles_type` (`type_salle_id`),
  KEY `fk_salles_batiment` (`batiment_id`),
  CONSTRAINT `fk_salles_type`    FOREIGN KEY (`type_salle_id`) REFERENCES `types_salle` (`id`),
  CONSTRAINT `fk_salles_batiment` FOREIGN KEY (`batiment_id`)   REFERENCES `batiments` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `equipements` (
  `id`      INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `libelle` VARCHAR(100) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_equipements_libelle` (`libelle`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `salle_equipements` (
  `salle_id`      INT UNSIGNED NOT NULL,
  `equipement_id` INT UNSIGNED NOT NULL,
  PRIMARY KEY (`salle_id`, `equipement_id`),
  KEY `fk_se_equipement` (`equipement_id`),
  CONSTRAINT `fk_se_salle`      FOREIGN KEY (`salle_id`)      REFERENCES `salles` (`id`)      ON DELETE CASCADE,
  CONSTRAINT `fk_se_equipement` FOREIGN KEY (`equipement_id`) REFERENCES `equipements` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `utilisateurs` (
  `id`            INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `nom`           VARCHAR(100) NOT NULL,
  `prenom`        VARCHAR(100) NOT NULL,
  `email`         VARCHAR(150) NOT NULL,
  `mot_de_passe`  VARCHAR(256) NOT NULL COMMENT 'hash SHA-256',
  `role`          ENUM('ADMIN','GESTIONNAIRE','ENSEIGNANT','ETUDIANT') NOT NULL,
  `actif`         TINYINT(1) NOT NULL DEFAULT 1,
  `date_creation` TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_utilisateurs_email` (`email`),
  KEY `idx_utilisateurs_role` (`role`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `classes` (
  `id`       INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `nom`      VARCHAR(50) NOT NULL,
  `filiere`  VARCHAR(100) DEFAULT NULL,
  `effectif` INT UNSIGNED NOT NULL DEFAULT 0,
  `niveau`   VARCHAR(20) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_classes_nom` (`nom`),
  KEY `idx_classes_niveau` (`niveau`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `matieres` (
  `id`             INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `code`           VARCHAR(20) NOT NULL,
  `libelle`        VARCHAR(150) NOT NULL,
  `volume_horaire` INT UNSIGNED NOT NULL DEFAULT 0,
  `couleur`        VARCHAR(7) NOT NULL DEFAULT '#3498db',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uq_matieres_code` (`code`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `cours` (
  `id`            INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `matiere_id`    INT UNSIGNED NOT NULL,
  `enseignant_id` INT UNSIGNED NOT NULL,
  `classe_id`     INT UNSIGNED NOT NULL,
  `salle_id`      INT UNSIGNED DEFAULT NULL,
  `jour_semaine`  TINYINT UNSIGNED NOT NULL COMMENT '1=Lundi ... 6=Samedi',
  `heure_debut`   TIME NOT NULL,
  `duree_minutes` SMALLINT UNSIGNED NOT NULL DEFAULT 90,
  `type_cours`    ENUM('CM','TD','TP') NOT NULL DEFAULT 'CM',
  `recurrent`     TINYINT(1) NOT NULL DEFAULT 1,
  `date_debut`    DATE DEFAULT NULL,
  `date_fin`      DATE DEFAULT NULL,
  `commentaire`   TEXT DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_cours_matiere`    (`matiere_id`),
  KEY `fk_cours_enseignant` (`enseignant_id`),
  KEY `fk_cours_classe`     (`classe_id`),
  KEY `fk_cours_salle`      (`salle_id`),
  KEY `idx_cours_jour`      (`jour_semaine`),
  CONSTRAINT `fk_cours_matiere`    FOREIGN KEY (`matiere_id`)    REFERENCES `matieres`     (`id`),
  CONSTRAINT `fk_cours_enseignant` FOREIGN KEY (`enseignant_id`) REFERENCES `utilisateurs` (`id`),
  CONSTRAINT `fk_cours_classe`     FOREIGN KEY (`classe_id`)     REFERENCES `classes`      (`id`),
  CONSTRAINT `fk_cours_salle`      FOREIGN KEY (`salle_id`)      REFERENCES `salles`       (`id`),
  CONSTRAINT `ck_cours_jour` CHECK (`jour_semaine` BETWEEN 1 AND 7)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `reservations` (
  `id`               INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `salle_id`         INT UNSIGNED NOT NULL,
  `utilisateur_id`   INT UNSIGNED NOT NULL,
  `titre`            VARCHAR(200) NOT NULL,
  `description`      TEXT DEFAULT NULL,
  `date_reservation` DATE NOT NULL,
  `heure_debut`      TIME NOT NULL,
  `heure_fin`        TIME NOT NULL,
  `statut`           ENUM('EN_ATTENTE','CONFIRMEE','ANNULEE') NOT NULL DEFAULT 'CONFIRMEE',
  `date_creation`    TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_res_salle`       (`salle_id`),
  KEY `fk_res_utilisateur` (`utilisateur_id`),
  KEY `idx_res_date`       (`date_reservation`),
  CONSTRAINT `fk_res_salle`       FOREIGN KEY (`salle_id`)       REFERENCES `salles`       (`id`),
  CONSTRAINT `fk_res_utilisateur` FOREIGN KEY (`utilisateur_id`) REFERENCES `utilisateurs` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE `notifications` (
  `id`             INT UNSIGNED NOT NULL AUTO_INCREMENT,
  `utilisateur_id` INT UNSIGNED NOT NULL,
  `message`        TEXT NOT NULL,
  `type`           ENUM('INFO','ALERTE','CONFLIT','CHANGEMENT') NOT NULL DEFAULT 'INFO',
  `lue`            TINYINT(1) NOT NULL DEFAULT 0,
  `date_creation`  TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`id`),
  KEY `fk_notif_utilisateur` (`utilisateur_id`),
  KEY `idx_notif_lue`        (`lue`),
  CONSTRAINT `fk_notif_utilisateur` FOREIGN KEY (`utilisateur_id`) REFERENCES `utilisateurs` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

