-- ============================================
-- VUES
-- ============================================
CREATE OR REPLACE VIEW `v_cours_complet` AS
SELECT
    c.id,
    m.libelle        AS matiere,
    m.couleur,
    CONCAT(u.prenom, ' ', u.nom) AS enseignant,
    cl.nom           AS classe,
    s.numero         AS salle_numero,
    s.nom            AS salle_nom,
    b.nom            AS batiment,
    CASE c.jour_semaine
        WHEN 1 THEN 'Lundi'   WHEN 2 THEN 'Mardi'
        WHEN 3 THEN 'Mercredi' WHEN 4 THEN 'Jeudi'
        WHEN 5 THEN 'Vendredi' WHEN 6 THEN 'Samedi'
        ELSE 'Dimanche'
    END              AS jour,
    c.heure_debut,
    c.duree_minutes,
    c.type_cours
FROM `cours` c
JOIN `matieres`     m  ON c.matiere_id    = m.id
JOIN `utilisateurs` u  ON c.enseignant_id = u.id
JOIN `classes`      cl ON c.classe_id     = cl.id
LEFT JOIN `salles`  s  ON c.salle_id      = s.id
LEFT JOIN `batiments` b ON s.batiment_id  = b.id;

CREATE OR REPLACE VIEW `v_salles_disponibles` AS
SELECT s.*, ts.libelle AS type_salle, b.nom AS batiment_nom
FROM `salles` s
JOIN `types_salle` ts ON s.type_salle_id = ts.id
JOIN `batiments`   b  ON s.batiment_id   = b.id
WHERE s.disponible = 1;

SET FOREIGN_KEY_CHECKS = 1;

